// Transform key-value rows into a config object
const config = {};
for (const item of $input.all()) {
  config[item.json.Key] = item.json.Value;
}

// Parse job titles
const jobTitles = (config.job_titles || 'Product Designer').split(',').map(t => t.trim());
const scoreThreshold = parseFloat(config.score_threshold || '4.0');
const scanBudget = parseInt(config.scan_budget_daily || '200');

return [{ json: { config, jobTitles, scoreThreshold, scanBudget } }];

const sites = [
  // TIER 1 — scan every run
  { name: 'Greenhouse', domain: 'greenhouse.io', tier: 1, rendering: 'static', enabled: true },
  { name: 'Lever', domain: 'lever.co', tier: 1, rendering: 'static', enabled: true },
  { name: 'Ashby', domain: 'ashbyhq.com', tier: 1, rendering: 'static', enabled: true },
  { name: 'Wellfound', domain: 'wellfound.com', tier: 1, rendering: 'static', enabled: true },
  { name: 'Workday', domain: 'myworkdayjobs.com', tier: 1, rendering: 'js_spa', enabled: true },
  { name: 'SmartRecruiters', domain: 'jobs.smartrecruiters.com', tier: 1, rendering: 'static', enabled: true },
  { name: 'JazzHR', domain: 'applytojob.com', tier: 1, rendering: 'static', enabled: true },
  { name: 'Jobvite', domain: 'jobs.jobvite.com', tier: 1, rendering: 'static', enabled: true },
  { name: 'BreezyHR', domain: 'breezy.hr', tier: 1, rendering: 'static', enabled: true },
  { name: 'Teamtailor', domain: 'teamtailor.com', tier: 1, rendering: 'static', enabled: true },
  { name: 'Recruitee', domain: 'recruitee.com', tier: 1, rendering: 'static', enabled: true },
  { name: 'Workable', domain: 'jobs.workable.com', tier: 1, rendering: 'static', enabled: true },
  { name: 'Builtin', domain: 'builtin.com', tier: 1, rendering: 'static', enabled: true },
  { name: 'Pinpoint', domain: 'pinpointhq.com', tier: 1, rendering: 'static', enabled: true },
  { name: 'Homerun', domain: 'homerun.co', tier: 1, rendering: 'static', enabled: true },
  // TIER 2 — rotate in groups
  { name: 'iCIMS', domain: 'icims.com', tier: 2, rendering: 'js_spa', enabled: true },
  { name: 'Oracle Cloud', domain: 'oraclecloud.com', tier: 2, rendering: 'js_spa', enabled: true },
  { name: 'Rippling', domain: 'rippling.com', tier: 2, rendering: 'static', enabled: true },
  { name: 'Gusto', domain: 'jobs.gusto.com', tier: 2, rendering: 'static', enabled: true },
  { name: 'Dover', domain: 'dover.io', tier: 2, rendering: 'static', enabled: true },
  { name: 'Gem', domain: 'gem.com', tier: 2, rendering: 'static', enabled: true },
  { name: 'Trakstar', domain: 'hire.trakstar.com', tier: 2, rendering: 'static', enabled: true },
  { name: 'JazzHR Cats', domain: 'catsone.com', tier: 2, rendering: 'static', enabled: true },
  { name: 'Keka', domain: 'keka.com', tier: 2, rendering: 'static', enabled: true },
  { name: 'Paylocity', domain: 'recruiting.paylocity.com', tier: 2, rendering: 'static', enabled: true },
  { name: 'CareerPuck', domain: 'careerpuck.com', tier: 2, rendering: 'static', enabled: true },
  { name: 'TalentReef', domain: 'jobappnetwork.com', tier: 2, rendering: 'static', enabled: true },
  { name: 'TriNet', domain: 'trinethire.com', tier: 2, rendering: 'static', enabled: true },
  { name: 'Factorial', domain: 'factorialhr.com', tier: 2, rendering: 'static', enabled: true },
  { name: 'Y Combinator', domain: 'workatastartup.com', tier: 2, rendering: 'static', enabled: true },
  { name: 'Glassdoor', domain: 'glassdoor.com', tier: 2, rendering: 'js_spa', enabled: true },
  { name: 'Remote Rocketship', domain: 'remoterocketship.com', tier: 2, rendering: 'static', enabled: true },
  { name: 'Notion Jobs', domain: 'notion.site', tier: 2, rendering: 'static', enabled: true },
  // LinkedIn: excluded from site: queries — JS-rendered, blocks crawlers
  // Use ad-hoc pipeline (Workflow 02) for LinkedIn URLs
  { name: 'LinkedIn', domain: 'linkedin.com', tier: 2, rendering: 'js_spa', enabled: false, note: 'LinkedIn blocks site: queries. Submit URLs via ad-hoc webhook instead.' }
];

const { jobTitles, scanBudget } = $('Parse Config').first().json;

// Tier 1 sites — always scan
const tier1 = sites.filter(s => s.tier === 1 && s.enabled);

// Tier 2 rotation — cycle groups of 8 by day of week
const tier2 = sites.filter(s => s.tier === 2 && s.enabled);
const dayIndex = new Date().getDay(); // 0-6
const groupSize = 8;
const offset = (dayIndex * groupSize) % tier2.length;
const tier2Today = [...tier2.slice(offset, offset + groupSize), ...tier2.slice(0, Math.max(0, offset + groupSize - tier2.length))];

const activeSites = [...tier1, ...tier2Today];

// Build query combos: title x site
const combos = [];
for (const title of jobTitles) {
  for (const site of activeSites) {
    combos.push({ title, site });
  }
}

return combos.map(c => ({ json: c }));

const results = [];
const inputItem = $input.first().json;
const searchTitle = $('Loop Over Query Combos').item.json.title;
const site = $('Loop Over Query Combos').item.json.site;

// Handle SerpAPI error
if (inputItem.error || !inputItem.organic_results) {
  return [{ json: { results: [], title: searchTitle, site: site.name, error: inputItem.error || 'No results' } }];
}

for (const r of (inputItem.organic_results || [])) {
  const url = r.link || '';
  const domain = url ? new URL(url).hostname.replace('www.', '') : '';
  const company = r.displayed_link ? r.displayed_link.split(' › ')[0] : domain.split('.')[0];

  // Generate dedup key
  const dedupKey = `${company.toLowerCase()}|${(r.title || '').toLowerCase()}|${domain}`;

  results.push({
    id: `${site.name.toLowerCase().replace(/\s/g, '_')}_${Date.now()}_${Math.random().toString(36).substring(2, 6)}`,
    source: site.name,
    company: company,
    title: r.title || '',
    url: url,
    snippet: (r.snippet || '').substring(0, 500),
    dateFound: new Date().toISOString(),
    freshnessHours: 12,
    status: 'New',
    dedupKey: dedupKey,
    rendering: site.rendering
  });
}

return results.map(r => ({ json: r }));

// Get existing dedup keys from the sheet
const existingKeys = new Set($('Read Pipeline for Dedup').all().map(i => i.json['Dedup Key']).filter(Boolean));

// Filter incoming results to only new ones
const incoming = $('Parse Search Results').all();
const newListings = incoming.filter(i => i.json.dedupKey && !existingKeys.has(i.json.dedupKey));

if (newListings.length === 0) {
  return [{ json: { newListings: [], count: 0, message: 'No new listings' } }];
}

return newListings;

const raw = $input.first().json.output || $input.first().json.text || '';
let parsed = { decision: 'MAYBE', reason: 'Could not parse response' };
try {
  const match = raw.match(/\{[\s\S]*?\}/);
  if (match) parsed = JSON.parse(match[0]);
} catch(e) {
  parsed.reason = 'Parse error: ' + raw.substring(0, 100);
}

const sourceItem = $('Batch for Pre-Screen').item;
const newStatus = parsed.decision === 'REJECT' ? 'Pre-Rejected' : 'Pre-Screened';

return [{ json: { ...sourceItem.json, preScreenDecision: parsed.decision, preScreenReason: parsed.reason, status: newStatus } }];

const sourceItem = $('Filter Passed Pre-Screen').item;
const htmlResponse = $input.first().json;
let jdText = '';
let confidence = 'high';

if (htmlResponse.error || !htmlResponse) {
  // Fallback to snippet
  jdText = sourceItem.json['JD Snippet'] || '';
  confidence = 'low';
} else {
  const html = typeof htmlResponse === 'string' ? htmlResponse : JSON.stringify(htmlResponse);
  // Strip HTML tags and collapse whitespace
  jdText = html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .substring(0, 8000);

  // If content is very short, likely JS-rendered — fall back to snippet
  if (jdText.length < 200) {
    jdText = sourceItem.json['JD Snippet'] || jdText;
    confidence = 'low';
  }
}

return [{ json: { ...sourceItem.json, jdText, confidence } }];

const raw = $input.first().json.output || $input.first().json.text || '{}';
const sourceItem = $('Extract JD Text').item;
let eval_data = {};

try {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) eval_data = JSON.parse(match[0]);
} catch(e) {
  eval_data = { scores: {}, overall: 0, grade: 'F', summary: 'Parse error', confidence: 'low' };
}

const scores = eval_data.scores || {};

// Apply weights
const weights = { role_match: 0.20, skills: 0.20, seniority: 0.12, compensation: 0.10, geographic: 0.08, company_stage: 0.08, product_market: 0.07, growth: 0.07, interview_likelihood: 0.05, timeline: 0.03 };
const weightedScore = Object.keys(weights).reduce((sum, k) => sum + (scores[k] || 3) * weights[k], 0);

// Gate-pass logic
let finalScore = weightedScore;
let finalGrade = eval_data.grade || 'C';
if ((scores.role_match || 0) <= 1 || (scores.skills || 0) <= 1) {
  finalGrade = 'D';
  finalScore = Math.min(finalScore, 2.9);
}

// Freshness boost
const freshnessHours = eval_data.freshness_hours || 24;
let freshnessBoost = 0;
if (freshnessHours < 6) freshnessBoost = 0.3;
else if (freshnessHours < 24) freshnessBoost = 0.2;
const adjustedScore = Math.min(5, finalScore + freshnessBoost);

// Recalculate grade from adjusted score
if (finalGrade !== 'D' && finalGrade !== 'F') {
  if (adjustedScore >= 4.5) finalGrade = 'A';
  else if (adjustedScore >= 3.8) finalGrade = 'B';
  else if (adjustedScore >= 3.0) finalGrade = 'C';
  else if (adjustedScore >= 2.0) finalGrade = 'D';
  else finalGrade = 'F';
}

return [{ json: {
  ...sourceItem.json,
  eval: eval_data,
  scores,
  overall: parseFloat(weightedScore.toFixed(2)),
  grade: finalGrade,
  freshnessAdjustedScore: parseFloat(adjustedScore.toFixed(2)),
  status: 'Evaluated'
} }];

const raw = $input.first().json.output || $input.first().json.text || '{}';
const sourceItem = $('Check Threshold').item;
let cvData = {};
try {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) cvData = JSON.parse(match[0]);
} catch(e) { cvData = { title: 'Preston Bezant', summary: raw.substring(0, 200) }; }

// Build experience HTML
const expHtml = (cvData.experience || []).map(role => `
  <div class="role">
    <div class="role-header">
      <strong>${role.company}</strong> — ${role.role}
      <span class="dates">${role.dates} | ${role.location || ''}</span>
    </div>
    <ul>${(role.bullets || []).map(b => `<li>${b}</li>`).join('')}</ul>
  </div>`).join('');

// Build skills HTML  
const skills = cvData.skills || {};
const skillsHtml = [
  skills.design?.length ? `<div class="skill-group"><strong>Design:</strong> ${skills.design.join(', ')}</div>` : '',
  skills.technical?.length ? `<div class="skill-group"><strong>Technical:</strong> ${skills.technical.join(', ')}</div>` : '',
  skills.tools?.length ? `<div class="skill-group"><strong>Tools:</strong> ${skills.tools.join(', ')}</div>` : ''
].filter(Boolean).join('');

const contact = cvData.contact || {};

const cvHtml = `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>${cvData.title || 'Preston Bezant'} — CV</title><style>body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;max-width:800px;margin:0 auto;padding:40px 24px;color:#1a1a1a;line-height:1.5;font-size:14px}h1{font-size:24px;margin-bottom:4px}h2{font-size:16px;border-bottom:1px solid #ddd;padding-bottom:4px;margin-top:24px;margin-bottom:12px}h3{font-size:14px;margin-bottom:2px}.contact{color:#555;margin-bottom:24px;font-size:13px}.role{margin-bottom:16px}.role-header{display:flex;justify-content:space-between;flex-wrap:wrap}.dates{color:#666;font-size:12px}ul{margin:6px 0;padding-left:20px}li{margin-bottom:4px}.skill-group{margin-bottom:6px}</style></head><body><h1>${contact.name || 'Preston Bezant'}</h1><div class="title-line">${cvData.title || ''}</div><div class="contact">${contact.email || ''} | ${contact.phone || ''} | ${contact.portfolio || ''} | ${contact.location || ''}</div><h2>Summary</h2><p>${cvData.summary || ''}</p><h2>Experience</h2>${expHtml}<h2>Skills</h2>${skillsHtml}<h2>Education</h2>${(cvData.education || []).map(e => `<div><strong>${e.degree}</strong> — ${e.school} (${e.dates})</div>`).join('')}</body></html>`;

return [{ json: { ...sourceItem.json, cvData, cvHtml, cvVersion: 1 } }];

// Parse cover letter from the Cover Letter Agent output
const clRaw = $('Cover Letter AI Agent').item.json.output || '';
const prepRaw = $input.first().json.output || '{}';

let coverLetter = {};
try { const m = clRaw.match(/\{[\s\S]*\}/); if(m) coverLetter = JSON.parse(m[0]); } catch(e) {}

let prepAnswers = {};
try { const m = prepRaw.match(/\{[\s\S]*\}/); if(m) prepAnswers = JSON.parse(m[0]); } catch(e) {}

// Build cover letter HTML
const clHtml = `<div style="font-family:sans-serif;max-width:700px;margin:0 auto;padding:40px 24px;">
  <p>${new Date().toLocaleDateString('en-US', {year:'numeric',month:'long',day:'numeric'})}</p>
  <p>${coverLetter.salutation || 'Hi Hiring Team,'}</p>
  <p>${coverLetter.paragraph_1 || ''}</p>
  <p>${coverLetter.paragraph_2 || ''}</p>
  <p>${coverLetter.paragraph_3 || ''}</p>
  <p style="white-space:pre-line">${coverLetter.closing || 'Best,\nPreston Bezant'}</p>
</div>`;

const sourceItem = $('Inject CV Template').item;
return [{ json: { ...sourceItem.json, coverLetter, clHtml, prepAnswers } }];

